  "title": "财务规划",
  "subtitle": "",
  "events": [
    {
      "date": "第3个月",
      "title": "灯塔验证与方案固化",
      "description": "完成中航光电等标杆客户验证，交付最小可行方案并固化销售工具包。预算71万元，严格按里程碑分配，涵盖人力、专利与云服务、物料及推广费用。设立独立监管账户，支出需双负责人联签。以客户验收通过率≥90%为硬性节点，未达标则暂停拨付。"
    },
    {
      "date": "第6个月",
      "title": "生态筑基与线索转化",
      "description": "举办“虚实协同”产教对接会，获取50+高质量线索并实现首轮转化。预算14万元，聚焦人力与推广。以线索转化率≥30%为进度考核节点。资金需求优先通过哈工大创新创业基金（20万）、哈尔滨市“雏鹰计划”（30万）等政策性融资保障，避免早期股权稀释。"
    },
    {
      "date": "全程",
      "title": "风险管控与应急保障",
      "description": "建立资金风险管控机制：严禁跨科目挪用；未达里程碑则启动预算重审；针对技术稳定性核心风险，预留5万元专项攻关备用金，联动哈工大研究中心建立72小时响应机制，启用传感器冗余校准等应急预案，确保项目主线稳步推进。"
    }
  ]
}

